import java.util.*;class Player{public static void main(String[]a){var s=new Scanner(System.in);int lx=s.nextInt(),ly=s.nextInt(),tx=s.nextInt(),ty=s.nextInt();for(;;){s.nextInt();var d="";if(ty>ly){d+="N";ty--;}else if(ty<ly){d+="S";ty++;}if(tx>lx){d+="W";tx--;}else if(tx<lx){d+="E";tx++;}System.out.println(d);}}}